/**
 * @summary List voters for an election
 */
export const getListVotersUrl = (params: ListVotersParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/voters?${stringifiedParams}`
    : `/api/voters`;
};

export const listVoters = async (
  params: ListVotersParams,
  options?: RequestInit,
): Promise<VotersResponse> => {
  return customFetch<VotersResponse>(getListVotersUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListVotersQueryKey = (params?: ListVotersParams) => {
  return [`/api/voters`, ...(params ? [params] : [])] as const;
};

export const getListVotersQueryOptions = <
  TData = Awaited<ReturnType<typeof listVoters>>,
  TError = ErrorType<unknown>,
>(
  params: ListVotersParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listVoters>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListVotersQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listVoters>>> = ({
    signal,
  }) => listVoters(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listVoters>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListVotersQueryResult = NonNullable<
  Awaited<ReturnType<typeof listVoters>>
>;
export type ListVotersQueryError = ErrorType<unknown>;

/**
 * @summary List voters for an election
 */

export function useListVoters<
  TData = Awaited<ReturnType<typeof listVoters>>,
  TError = ErrorType<unknown>,
>(
  params: ListVotersParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listVoters>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListVotersQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

